#include <iostream>
#include <fstream>
#include <string>
#include <sstream>
#include <unordered_map>

using namespace std;

int main() {
    string filename, wordToCount;
    int count = 0;

    // Get filename and word from the user
    cout << "Enter the filename: ";
    cin >> filename;
    cout << "Enter the word to count: ";
    cin >> wordToCount;

    // Open the file for reading
    ifstream file(filename);
    if (!file.is_open()) {
        cerr << "Error opening file: " << filename << endl;
        return 1;  // Indicate an error
    }

    // Use an unordered map to efficiently store word counts
    unordered_map<string, int> wordCounts;

    string line;
    while (getline(file, line)) {
        // Split the line into words using whitespace as a delimiter
        stringstream ss(line);
        string word;
        while (ss >> word) {
            // Convert to lowercase for case-insensitive counting
            transform(word.begin(), word.end(), word.begin(), ::tolower); 

            if (word == wordToCount) {
                wordCounts[word]++; 
            }
        }
    }

    // Print the count
    count = wordCounts[wordToCount];
    cout << "The word '" << wordToCount << "' appears " << count << " times in the file." << endl;

    file.close();
    return 0;
}
```

**Explanation:**

1. **Headers:**
   - `iostream`: For standard input/output (like `cin`, `cout`).
   - `fstream`: For file handling (`ifstream`).
   - `string`: For string manipulation.
   - `sstream`: For using `stringstream` to split lines into words.
   - `unordered_map`:  Provides efficient key-value storage (for counting word occurrences).

2. **Input:**
   - The program prompts the user to enter the filename and the word to search for.

3. **File Opening:**
   - `ifstream file(filename);` opens the file for reading.
   - Error handling checks if the file opened successfully.

4. **Word Counting with `unordered_map`:**
   - An `unordered_map<string, int> wordCounts` is created to store each word as a key and its count as the value. This allows for fast lookups and updates.
   - **Line-by-Line Processing:**
     - `getline(file, line)` reads each line from the file into the `line` string.
     - **Word Splitting:**
       - `stringstream ss(line);` creates a stringstream from the line.
       - `ss >> word` extracts words from the stringstream, separated by whitespace.
     - **Case-Insensitive Counting:**
       - `transform(word.begin(), word.end(), word.begin(), ::tolower);` converts each extracted word to lowercase for case-insensitive comparison.
     - **Counting:**
       - If the extracted `word` matches `wordToCount`, `wordCounts[word]++` increments the count for that word in the map.

5. **Output:**
   - After processing the entire file, `count = wordCounts[wordToCount]` retrieves the final count from the map.
   - The result is printed to the console.

6. **File Closure:**
   - `file.close();` closes the file stream.



**Key Points:**

- **Efficiency:** Using `unordered_map` makes word counting very efficient, especially for large files, as lookups and insertions are generally O(1) on average.
- **Case-Insensitivity:** Converting words to lowercase ensures accurate counting regardless of case variations in the file.



